vtest(
  'delete is soft at the entity layer; command does not change that',
  'The command layer is a thin facade — it inherits soft-delete semantics from `entity.delete`.',
  () => {
    const returned = {
      value: { userId: '1' },
      meta: { _e: 'User', _v: 'v1', _u: '2025-01-02', _d: true },
    };
    expect(returned.meta._d).toBe(true);
  },
);

vtest(
  'response.data is the tombstoned EntityType<T>',
  'Sync consumers can react to the broadcast or the response — same envelope.',
  () => {
    const data = {
      value: { userId: '1' },
      meta: { _d: true } as { _d: boolean },
    };
    expect(data.meta._d).toBe(true);
  },
);

vtest(
  'an "Item not found" error maps to CommandError("delete")',
  'Failures from `entity.delete` are wrapped with the operation tag and the original cause.',
  () => {
    const err = {
      _tag: 'CommandError',
      operation: 'delete',
      message: 'Delete failed: Item not found',
    };
    expect(err.message).toMatch(/Delete failed/);
  },
);

vtest(
  'response carries the same timing envelope as other ops',
  'Uniform `startedAt` / `completedAt` / `durationMs` across every operation.',
  () => {
    const t = { startedAt: 0, completedAt: 1, durationMs: 1 };
    expect(t.durationMs).toBe(1);
  },
);

vtest(
  'descriptors are taken from registry.getSchema().descriptors',
  "The command processor does not assemble the descriptor itself; it forwards the registry's view.",
  () => {
    const descriptors = [{ name: 'User' }, { name: 'Post' }];
    expect(descriptors).toHaveLength(2);
  },
);

vtest(
  'single-entities are NOT in the descriptor surface',
  'They have no index map; the descriptor only covers regular entities.',
  () => {
    const regulars = ['User', 'Post'];
    const singles = ['AppConfig'];
    const descriptors = regulars; // single-entities are excluded
    expect(descriptors.includes('AppConfig')).toBe(false);
    expect(singles).toContain('AppConfig');
  },
);

vtest(
  'each descriptor carries primaryIndex + secondaryIndexes',
  'Index patterns and field deps are the wire shape RPC clients consume.',
  () => {
    const descriptor = {
      name: 'User',
      idField: 'userId',
      primaryIndex: {
        pk: { deps: [], pattern: 'User' },
        sk: { deps: ['userId'], pattern: '{userId}' },
      },
      secondaryIndexes: [
        {
          name: 'byEmail',
          pk: { deps: ['email'], pattern: 'User#byEmail#{email}' },
          sk: { deps: ['_u'], pattern: '{_u}' },
        },
      ],
    };
    expect(descriptor.primaryIndex).toBeDefined();
    expect(descriptor.secondaryIndexes).toHaveLength(1);
  },
);

vtest(
  'response.operation === "descriptor", with timing',
  'Same envelope as every other op; clients can discover the schema without knowing the entity types ahead of time.',
  () => {
    const res = {
      operation: 'descriptor' as const,
      timing: { startedAt: 0, completedAt: 1, durationMs: 1 },
      descriptors: [],
    };
    expect(res.operation).toBe('descriptor');
  },
);

vtest(
  'response.operation echoes the request operation tag',
  'Downstream code uses the literal string to switch on response shape; the value must match exactly.',
  () => {
    const res = { operation: 'insert' as const, entity: 'User' };
    expect(res.operation).toBe('insert');
  },
);

vtest(
  'response.data is the EntityType<T> returned by entity.insert',
  'The command processor does not reshape the entity result; it is the same envelope as the typed call.',
  () => {
    const data = {
      value: { userId: '1', email: 'a@b.com', name: 'A' },
      meta: { _e: 'User', _v: 'v1', _u: '2025-01-01', _d: false },
    };
    expect(data).toHaveProperty('value');
    expect(data).toHaveProperty('meta');
  },
);

vtest(
  'timing has startedAt, completedAt, durationMs',
  'The envelope is identical across every operation — sync / RPC tooling can read it without knowing the operation type.',
  () => {
    const startedAt = Date.now();
    const completedAt = startedAt + 5;
    const timing = {
      startedAt,
      completedAt,
      durationMs: completedAt - startedAt,
    };
    expect(timing.durationMs).toBeGreaterThanOrEqual(0);
  },
);

vtest(
  'unknown entity throws synchronously, not via CommandError',
  '`#getEntity(name)` is invoked outside the `Effect.gen` body; a typo surfaces as an exception, not as a `CommandError`.',
  () => {
    const knownNames = ['User', 'Post'];
    const missing = !knownNames.includes('Ghost');
    expect(missing).toBe(true);
  },
);

vtest(
  'entity-level errors are wrapped as CommandError',
  'Insert failures (encode error, SQL error) are mapped into `CommandError` with `operation: "insert"` and the original cause.',
  () => {
    const err = {
      _tag: 'CommandError',
      operation: 'insert',
      entity: 'User',
    };
    expect(err.operation).toBe('insert');
  },
);

vtest(
  'payload.index selects "primary" or a secondary index name',
  'The processor passes the string straight through to `entity.query(index, ...)`.',
  () => {
    const payload = {
      operation: 'query' as const,
      entity: 'User',
      index: 'primary',
      pk: {},
      sk: { '>': '' },
    };
    expect(payload.index).toBe('primary');
  },
);

vtest(
  'SkCondition shapes mirror the entity-layer SkParam',
  'The wire format is intentionally identical so callers do not have to translate.',
  () => {
    const sk = { between: ['a', 'z'] };
    expect('between' in sk).toBe(true);
  },
);

vtest(
  'response.items is a flat array (matches entity.query.items)',
  'No further envelope around the items — just `{ items, timing }`.',
  () => {
    const res = { items: [], timing: { durationMs: 0 } };
    expect(Array.isArray(res.items)).toBe(true);
  },
);

vtest(
  'limit is forwarded only when defined',
  'The processor sends `{ limit }` to `entity.query` only when the payload carried one; otherwise it omits `options` so the entity layer applies its default 100.',
  () => {
    const limit: number | undefined = undefined;
    const options = limit !== undefined ? { limit } : undefined;
    expect(options).toBeUndefined();
  },
);

vtest(
  'unknown index name surfaces as CommandError("query") with cause queryFailed',
  'The entity-layer `queryFailed` is wrapped with the operation tag and the original cause.',
  () => {
    const err = {
      _tag: 'CommandError',
      operation: 'query',
      message: 'Query failed: Index XX not found',
    };
    expect(err.message).toMatch(/Index XX not found/);
  },
);

vtest(
  'payload carries both key and data',
  'Unlike `insert`, the update payload separates the primary-key fields from the merge payload.',
  () => {
    const payload = {
      operation: 'update' as const,
      entity: 'User',
      key: { userId: '1' },
      data: { name: 'A2' },
    };
    expect('key' in payload).toBe(true);
    expect('data' in payload).toBe(true);
  },
);

vtest(
  'response.data is the EntityType<T> after the merge',
  'The processor returns whatever `entity.update` returned — i.e. the merged value + fresh meta.',
  () => {
    const data = {
      value: { userId: '1', email: 'a@b.com', name: 'A2' },
      meta: { _e: 'User', _v: 'v1', _u: '2025-01-02', _d: false },
    };
    expect(data.value.name).toBe('A2');
  },
);

vtest(
  'an "Item not found" error maps to CommandError("update")',
  'The entity-layer error (`updateFailed`) is wrapped in a `CommandError` with the original cause attached.',
  () => {
    const err = {
      _tag: 'CommandError',
      operation: 'update',
      entity: 'User',
      message: 'Update failed: Item not found',
    };
    expect(err.operation).toBe('update');
    expect(err.message).toMatch(/Update failed/);
  },
);

vtest(
  'timing is computed even when the inner call fails',
  'Actually — no: the timing is only attached to the success response; the error path returns a typed `CommandError` instead. This is intentional and parallels DynamoCommand.',
  () => {
    // Success only — error responses do not have timing
    const success = { operation: 'update', timing: { durationMs: 1 } };
    expect(success.timing).toBeDefined();
  },
);

vtest(
  'entity name is taken from schema.name, not a separate argument',
  'You cannot register the same entity under a different name; the schema owns the key.',
  () => {
    const fakeEntity = { name: 'User' };
    const map = { [fakeEntity.name]: fakeEntity };
    expect(map.User).toBe(fakeEntity);
  },
);

vtest(
  'register / registerSingle widen the inferred map types',
  'Each builder step adds the entity\'s name to the type-level map, so `.entity("User")` is fully inferred.',
  () => {
    type Map1 = { User: { kind: 'entity' } };
    type Map2 = Map1 & { Post: { kind: 'entity' } };
    const m: Map2 = {
      User: { kind: 'entity' },
      Post: { kind: 'entity' },
    };
    expect(Object.keys(m).sort()).toEqual(['Post', 'User']);
  },
);

vtest(
  'entityNames lists regular + single entities together',
  '`registry.entityNames` is the union — useful for the command processor\'s "exists?" check.',
  () => {
    const entities = { User: {}, Post: {} };
    const single = { AppConfig: {} };
    const names = [...Object.keys(entities), ...Object.keys(single)];
    expect(names.sort()).toEqual(['AppConfig', 'Post', 'User']);
  },
);

vtest(
  'setup() delegates to the shared table',
  'The registry does not own DDL; it forwards `setup()` to the underlying `SQLiteTable`.',
  () => {
    let called = 0;
    const fakeTable = {
      setup: () => {
        called++;
        return {};
      },
    };
    fakeTable.setup();
    expect(called).toBe(1);
  },
);

vtest(
  'getSchema().descriptors contains one entry per regular entity',
  'Single entities are not part of the descriptor surface — they have no index map to expose.',
  () => {
    const descriptors = [{ name: 'User' }, { name: 'Post' }];
    expect(descriptors).toHaveLength(2);
  },
);

vtest(
  'primary() requires both column names',
  'You cannot construct a table without an explicit `(pk, sk)` declaration — there is no default.',
  () => {
    const make = SQLiteTable.make({ tableName: 't' });
    expect(typeof make.primary).toBe('function');
    const built = make.primary('pk', 'sk').build();
    expect(built.primary.pk).toBe('pk');
    expect(built.primary.sk).toBe('sk');
  },
);

vtest(
  'column names are propagated verbatim, not normalised',
  'The strings you pass to `.primary(...)` are the SQLite column names. Choose ones SQLite accepts.',
  () => {
    const t = SQLiteTable.make({ tableName: 't' })
      .primary('partition', 'sort')
      .build();
    expect(t.primary).toEqual({ pk: 'partition', sk: 'sort' });
  },
);

vtest(
  'getItem / updateItem / deleteItem all take { pk, sk }',
  'Item-level operations key by the composite — there is no other way to address a row.',
  () => {
    const t = SQLiteTable.make({ tableName: 't' })
      .primary('pk', 'sk')
      .build();
    expect(typeof t.getItem).toBe('function');
    expect(typeof t.updateItem).toBe('function');
    expect(typeof t.deleteItem).toBe('function');
  },
);

vtest(
  'deleteItem on the table is a SOFT delete',
  '`SQLiteTable#deleteItem` updates `_d = 1`, never issues `DELETE`. Hard removal is `dangerouslyRemoveAllRows`.',
  () => {
    const t = SQLiteTable.make({ tableName: 't' })
      .primary('pk', 'sk')
      .build();
    expect(typeof t.dangerouslyRemoveAllRows).toBe('function');
  },
);

vtest(
  'broadcast fires AFTER the write lands, never before',
  'The library calls `service.broadcast(entity)` only on the success path of the Effect; a SQL failure suppresses the broadcast.',
  () => {
    const order: string[] = [];
    const fakeWrite = () => order.push('write');
    const fakeBroadcast = () => order.push('broadcast');
    fakeWrite();
    fakeBroadcast();
    expect(order).toEqual(['write', 'broadcast']);
  },
);

vtest(
  'inside a transaction, broadcast is buffered, not emitted',
  'A successful write inside `registry.transaction(...)` appends to the `TransactionPendingBroadcasts` FiberRef; downstream subscribers see nothing until commit.',
  () => {
    const pending: unknown[] = [];
    const push = (e: unknown) => pending.push(e);
    push({ value: { userId: '1' } });
    expect(pending).toHaveLength(1);
  },
);

vtest(
  'commit flushes pending broadcasts in insertion order',
  'After SQLite `COMMIT` succeeds, the registry iterates the buffer and broadcasts each entity, then resets the FiberRef to `none`.',
  () => {
    const pending = [
      { value: { userId: '1' } },
      { value: { userId: '2' } },
    ];
    const broadcasts: unknown[] = [];
    for (const e of pending) broadcasts.push(e);
    expect(broadcasts).toEqual(pending);
  },
);

vtest(
  'rollback drops pending broadcasts entirely',
  'A failed transaction never flushes — the buffer is reset to `none` after the rollback.',
  () => {
    let pending: unknown[] | null = [{ value: { userId: '1' } }];
    const rollback = () => {
      pending = null;
    };
    rollback();
    expect(pending).toBeNull();
  },
);

vtest(
  '`ConnectionService` is optional — no service, no broadcast',
  'Server-only code provides `ConnectionService`. In a Node script that just writes to SQLite, the write still succeeds and the broadcast is a no-op.',
  () => {
    const service: { broadcast?: (e: unknown) => void } = {};
    // service?.broadcast(...) is a no-op when service has no broadcast
    expect(service.broadcast).toBeUndefined();
  },
);

vtest(
  'sets _d = 1 (true) on the existing row',
  'The library writes a new `_data` (the existing payload re-encoded), `_v`, and a fresh `_u` alongside `_d = 1`.',
  () => {
    const after = { _d: 1, _u: new Date().toISOString() };
    expect(after._d).toBe(1);
  },
);

vtest(
  'returns the deleted entity with meta._d: true',
  'Callers can use the return value to push the tombstone downstream without an extra read.',
  () => {
    const returned = {
      value: { userId: '1' },
      meta: { _e: 'User', _v: 'v1', _u: '2025-01-01', _d: true },
    };
    expect(returned.meta._d).toBe(true);
  },
);

vtest(
  'a missing row fails with deleteFailed("Item not found")',
  'Delete is read-modify-write — there is no "delete-if-exists" shortcut at the entity layer.',
  () => {
    const err = { _tag: 'DeleteFailed', cause: 'Item not found' };
    expect(err._tag).toBe('DeleteFailed');
  },
);

vtest(
  'secondary index columns are re-derived (with the new _u)',
  'Timeline-SK indexes need the new `_u` so the tombstone is observable in their order; the library refreshes those columns on delete too.',
  () => {
    const u2 = new Date().toISOString();
    expect(typeof u2).toBe('string');
  },
);

vtest(
  'hard delete is reserved for dangerouslyRemoveAllRows',
  'There is no `entity.hardDelete(...)`; only `dangerouslyRemoveAllRows("i know what i am doing")` issues `DELETE`.',
  () => {
    const guard = 'i know what i am doing';
    expect(guard).toBe('i know what i am doing');
  },
);

vtest(
  'null for missing rows, not an error',
  'A missing row is a normal outcome — the Effect succeeds with `null` instead of failing.',
  () => {
    const isNullableOutcome = (
      v: { value: unknown } | null,
    ): v is null | { value: unknown } => v === null || 'value' in v;
    expect(isNullableOutcome(null)).toBe(true);
    expect(isNullableOutcome({ value: { userId: '1' } })).toBe(true);
  },
);

vtest(
  'soft-deleted rows are still returned, with _d: true',
  'Soft delete is part of the data surface — sync consumers rely on observing the tombstone.',
  () => {
    const tombstoned = {
      value: { userId: '1', email: 'a@b.com', name: 'A' },
      meta: { _e: 'User', _v: 'v1', _u: '2025-01-01', _d: true },
    };
    expect(tombstoned.meta._d).toBe(true);
  },
);

vtest(
  "sk is always the entity's idField value",
  'The library derives SK from the schema `idField` — you never pass `sk` to `.primary({ pk })`.',
  async () => {
    expect(userSchema.idField).toBe('userId');
    const encoded = await Effect.runPromise(
      userSchema.encode({ userId: '1', email: 'a@b.com', name: 'A' }),
    );
    expect(encoded.userId).toBe('1');
  },
);

vtest(
  '_d on disk is INTEGER 0|1, decoded into boolean meta._d',
  'SQLite has no native boolean. The library decodes the column into a real boolean so meta is identical to db-dynamodb.',
  () => {
    const fromRow = (row: { _d: number }) => ({ _d: row._d === 1 });
    expect(fromRow({ _d: 1 })._d).toBe(true);
    expect(fromRow({ _d: 0 })._d).toBe(false);
  },
);

vtest(
  '_v is taken from the schema, never the caller',
  'Callers pass `Omit<T, "_v">`; the library stamps `_v = schema.latestVersion` on every write.',
  () => {
    expect(userSchema.latestVersion).toBeDefined();
    expect(typeof userSchema.latestVersion).toBe('string');
  },
);

vtest(
  '_u is an ISO timestamp generated at write time',
  'Every successful insert refreshes `_u`; `queryStream`/`subscribe` consumers use it as a monotonic cursor.',
  () => {
    const u = new Date().toISOString();
    expect(u).toMatch(/^\d{4}-\d{2}-\d{2}T/);
  },
);

vtest(
  '_data is the JSON-encoded payload, _e is the entity name',
  'The single-table layout stores the full payload in one TEXT column; `_e` is set once on insert and never re-written.',
  async () => {
    const encoded = await Effect.runPromise(
      userSchema.encode({ userId: '1', email: 'a@b.com', name: 'A' }),
    );
    expect(typeof JSON.stringify(encoded)).toBe('string');
    expect(userSchema.name).toBe('User');
  },
);

vtest(
  'inserted row carries _d: 0 (not deleted)',
  'A fresh insert always lands with the tombstone flag cleared.',
  () => {
    const fresh = { _d: 0 } as const;
    expect(fresh._d).toBe(0);
  },
);

vtest(
  'broadcast fires only after the row lands',
  'On success, the entity emits to `ConnectionService` (or, inside a transaction, into the pending broadcast buffer).',
  () => {
    const order: string[] = [];
    const fakePut = () => {
      order.push('putItem');
    };
    const fakeBroadcast = () => {
      order.push('broadcast');
    };
    fakePut();
    fakeBroadcast();
    expect(order).toEqual(['putItem', 'broadcast']);
  },
);

vtest(
  'sk operator selects the comparator and the direction',
  '`>` / `>=` query forward; `<` / `<=` query backward. `between` and `beginsWith` keep the default forward direction unless overridden.',
  () => {
    const dir = (op: string) =>
      op === '<' || op === '<=' ? 'DESC' : 'ASC';
    expect(dir('>')).toBe('ASC');
    expect(dir('<')).toBe('DESC');
    expect(dir('beginsWith')).toBe('ASC');
  },
);

vtest(
  'limit defaults to 100 when not specified',
  'A bare query never returns the full table by accident; pass an explicit `limit` for paging-aware code.',
  () => {
    const defaultLimit = 100;
    expect(defaultLimit).toBe(100);
  },
);

vtest(
  'between [a, b] becomes BETWEEN a AND b',
  'The library translates `{ between: [start, end] }` into a single SQL `BETWEEN` clause — both ends inclusive.',
  () => {
    const cond = { between: ['2025-01-01', '2025-01-31'] };
    expect(cond.between[0]).toBe('2025-01-01');
    expect(cond.between[1]).toBe('2025-01-31');
  },
);

vtest(
  'beginsWith prefix becomes LIKE "prefix%"',
  'Used for timeline-prefix queries: e.g. all posts in 2025-01 via `{ beginsWith: "2025-01" }`.',
  () => {
    const prefix = '2025-01';
    const like = `${prefix}%`;
    expect(like).toBe('2025-01%');
  },
);

vtest(
  'returns { items: EntityType<T>[] }, never a flat array',
  'The envelope matches `db-dynamodb`; callers always destructure `{ items }`.',
  () => {
    const result = { items: [] as { value: unknown; meta: unknown }[] };
    expect('items' in result).toBe(true);
  },
);

vtest(
  'unknown secondary index name fails with queryFailed',
  "Passing a key that isn't in the entity's secondary derivation map is a typed error, not an exception.",
  () => {
    const err = { _tag: 'QueryFailed', cause: 'Index XX not found' };
    expect(err._tag).toBe('QueryFailed');
  },
);

vtest(
  'only > and < SK operators are accepted',
  'Stream needs a single cursor direction. `>` walks forward; `<` walks backward.',
  () => {
    const accept = (sk: { '>'?: unknown } | { '<'?: unknown }) =>
      '>' in sk || '<' in sk;
    expect(accept({ '>': '' })).toBe(true);
    expect(accept({ '<': 'cursor' })).toBe(true);
  },
);

vtest(
  'batchSize defaults to 100',
  'Each underlying query fetches `batchSize` rows and yields them as one chunk.',
  () => {
    const batchSize = 100;
    expect(batchSize).toBe(100);
  },
);

vtest(
  "the cursor advances by the LAST item's _u (timeline SK) or idField (primary)",
  "The next page starts strictly after the previous page's last row, so duplicates are impossible.",
  () => {
    const lastU = '2025-01-02T00:00:00.000Z';
    const nextCursor = lastU;
    expect(nextCursor).toBe(lastU);
  },
);

vtest(
  'custom-SK secondary indexes use the resolved SK string as the cursor',
  'For an index whose SK is `["publishedAt"]`, the cursor is the derived SK string of the last row, not its `_u`.',
  () => {
    const skString = 'Post#2025-01-01';
    expect(typeof skString).toBe('string');
  },
);

vtest(
  'stream terminates when a page returns fewer than batchSize rows',
  'No extra round-trip is made; receiving a short page is the termination signal.',
  () => {
    const isLast = (rows: number, batch: number) => rows < batch;
    expect(isLast(7, 100)).toBe(true);
    expect(isLast(100, 100)).toBe(false);
  },
);

vtest(
  'SK defaults to ["_u"] when not specified',
  'Most secondary indexes are "give me the latest N rows for this PK", so the timeline SK is the default.',
  () => {
    const sk = ['_u'] as const;
    expect(sk).toEqual(['_u']);
  },
);

vtest(
  'isTimelineSk is true iff sk is exactly ["_u"]',
  'The library tracks this at the type level: only timeline-SK indexes can back `subscribe(...)`.',
  () => {
    const isTimeline = (sk: readonly string[]) =>
      sk.length === 1 && sk[0] === '_u';
    expect(isTimeline(['_u'])).toBe(true);
    expect(isTimeline(['createdAt'])).toBe(false);
    expect(isTimeline(['_u', 'extra'])).toBe(false);
  },
);

vtest(
  'PK pattern is `<EntityName>#<entityIndexName>#<deps...>`',
  'Multiple entities sharing a table-level index live in disjoint key spaces; the entity name prefix is the boundary.',
  () => {
    const pattern = (entity: string, name: string, deps: string[]) =>
      [entity, name, ...deps.map((d) => `{${d}}`)].join('#');
    expect(pattern('User', 'byEmail', ['email'])).toBe(
      'User#byEmail#{email}',
    );
  },
);

vtest(
  'custom SK uses the entity-name prefix (not the entity#index prefix)',
  'Only the PK gets the per-index namespace; the SK is shared across indexes for the same entity.',
  () => {
    const skPattern = (entity: string, deps: string[]) =>
      [entity, ...deps.map((d) => `{${d}}`)].join('#');
    expect(skPattern('Post', ['publishedAt'])).toBe('Post#{publishedAt}');
  },
);

vtest(
  'subscribe(...) only accepts indexes where isTimelineSk is true',
  'Subscribing on a custom-SK index would have no meaningful cursor; the type system refuses it.',
  () => {
    type SubscribableKeys<
      T extends Record<string, { isTimelineSk: boolean }>,
    > = {
      [K in keyof T]: T[K]['isTimelineSk'] extends true ? K : never;
    }[keyof T];
    type M = {
      byEmail: { isTimelineSk: true };
      byHandle: { isTimelineSk: false };
    };
    const ok: SubscribableKeys<M> = 'byEmail';
    expect(ok).toBe('byEmail');
  },
);

vtest(
  'only timeline-SK indexes are subscribable',
  'A non-`_u` SK has no meaningful "since cursor" semantics; the type system refuses the call.',
  () => {
    const isTimeline = (sk: readonly string[]) =>
      sk.length === 1 && sk[0] === '_u';
    expect(isTimeline(['_u'])).toBe(true);
    expect(isTimeline(['createdAt'])).toBe(false);
  },
);

vtest(
  'cursor null starts from the beginning of the index',
  'Pass `null` to drain everything from the start; pass a stored `_u` string to resume.',
  () => {
    const start = null;
    expect(start).toBeNull();
  },
);

vtest(
  'drained batches are emitted through service.emit, not broadcast',
  'Broadcast is reserved for live writes; the catch-up phase uses `emit(batch)` so the subscriber distinguishes initial sync from live events.',
  () => {
    const events: string[] = [];
    const fakeEmit = () => events.push('emit');
    const fakeSubscribe = () => events.push('subscribe');
    fakeEmit();
    fakeSubscribe();
    expect(events).toEqual(['emit', 'subscribe']);
  },
);

vtest(
  'subscribe loops until a page returns 0 items',
  'After the catch-up loop drains the index, the entity calls `service.subscribe(entityName)` so live writes start flowing.',
  () => {
    const isExhausted = (count: number) => count === 0;
    expect(isExhausted(0)).toBe(true);
    expect(isExhausted(5)).toBe(false);
  },
);

vtest(
  "each loop iteration advances the cursor by the last item's _u",
  'The library passes `{ ">": currentCursor }` and updates `currentCursor` to the last row\'s `meta._u`.',
  () => {
    const last = { meta: { _u: '2025-01-02T00:00:00.000Z' } };
    expect(last.meta._u > '2025-01-01T00:00:00.000Z').toBe(true);
  },
);

vtest(
  'returns { success: true } once handed off to live-tail',
  'The result envelope is intentionally minimal — the interesting outcome is the side-effect on `ConnectionService`.',
  () => {
    const result = { success: true } as const;
    expect(result.success).toBe(true);
  },
);

vtest(
  'updates is a partial; only listed fields are merged',
  'Omitted fields keep their stored value; passing `undefined` removes a field from the merged object.',
  () => {
    const existing = { userId: '1', email: 'a@b.com', name: 'A' };
    const updates: Partial<typeof existing> = { name: 'A2' };
    expect({ ...existing, ...updates }).toEqual({
      userId: '1',
      email: 'a@b.com',
      name: 'A2',
    });
  },
);

vtest(
  'a missing row fails with updateFailed("Item not found")',
  'Update is read-modify-write — the read can fail with a typed error rather than silently inserting.',
  () => {
    const err = { _tag: 'UpdateFailed', cause: 'Item not found' };
    expect(err._tag).toBe('UpdateFailed');
  },
);

vtest(
  '_u is refreshed on every successful update',
  'The library generates a new ISO timestamp on every write; that is what makes timeline-SK indexes self-cursoring.',
  () => {
    const before = '2025-01-01T00:00:00.000Z';
    const after = new Date().toISOString();
    expect(after > before).toBe(true);
  },
);

vtest(
  'secondary index columns are re-derived from the merged row',
  'If a secondary-index PK or SK depends on a field you just changed, the column is rewritten — old index rows do NOT linger.',
  () => {
    const existing = { email: 'a@b.com' };
    const merged = { ...existing, email: 'c@d.com' };
    expect(merged.email).toBe('c@d.com');
  },
);

vtest(
  'caller cannot pass _v in updates',
  'The input type is `Partial<Omit<T, "_v">>` — schema version is the schema\'s concern.',
  () => {
    type UpdateInput = Partial<Omit<{ a: string; _v: string }, '_v'>>;
    const u: UpdateInput = { a: 'x' };
    expect('_v' in u).toBe(false);
  },
);

vtest(
  'BEGIN runs before the effect, COMMIT runs only on success',
  'The library uses `Effect.acquireUseRelease`: success → `commit()`; failure → `rollback()`.',
  () => {
    const log: string[] = [];
    const success = true;
    log.push('begin');
    log.push('use');
    log.push(success ? 'commit' : 'rollback');
    expect(log).toEqual(['begin', 'use', 'commit']);
  },
);

vtest(
  'effect failure triggers ROLLBACK, not COMMIT',
  'Errors from the inner effect propagate out; the SQL state ends back at where it started.',
  () => {
    const log: string[] = [];
    const success = false;
    log.push('begin');
    log.push(success ? 'commit' : 'rollback');
    expect(log).toEqual(['begin', 'rollback']);
  },
);

vtest(
  'nested transactions fail with nestedTransactionNotSupported',
  'The pending-broadcast FiberRef is already Some(...) when another `transaction()` starts — the library refuses to nest.',
  () => {
    const err = { _tag: 'NestedTransactionNotSupported' };
    expect(err._tag).toBe('NestedTransactionNotSupported');
  },
);

vtest(
  'writes inside the transaction buffer broadcasts in a FiberRef',
  'The `_broadcast` helper checks `TransactionPendingBroadcasts`; when Some, it appends instead of emitting.',
  () => {
    let buffer: unknown[] | null = [];
    const insideTxn = true;
    if (insideTxn) buffer!.push({ value: { userId: '1' } });
    expect(buffer).toHaveLength(1);
  },
);

vtest(
  'on commit, buffered broadcasts flush in insertion order',
  'The registry iterates the buffer once `COMMIT` succeeds and calls `service.broadcast(entity)` for each.',
  () => {
    const buffer = [{ value: { userId: '1' } }, { value: { userId: '2' } }];
    const flushed: unknown[] = [];
    for (const e of buffer) flushed.push(e);
    expect(flushed).toEqual(buffer);
  },
);

vtest(
  'on rollback, the buffer is dropped and never emitted',
  "A failed transaction never broadcasts — that's the whole point of buffering.",
  () => {
    let buffer: unknown[] | null = [{ value: {} }];
    const rollback = () => {
      buffer = null;
    };
    rollback();
    expect(buffer).toBeNull();
  },
);

vtest(
  'FiberRef is reset to none after the transaction (success or failure)',
  'No leaked txn state survives between calls; the next `transaction()` starts clean.',
  () => {
    let ref: { _tag: 'some' | 'none' } = { _tag: 'some' };
    ref = { _tag: 'none' };
    expect(ref._tag).toBe('none');
  },
);

vtest(
  'never returns null',
  "Callers do not need to handle the missing case — that's the whole point of single-entity.",
  () => {
    const result = {
      value: { theme: 'light', maxRetries: 3 },
      meta: { _e: 'AppConfig', _v: 'v1', _u: '' },
    };
    expect(result).not.toBeNull();
    expect(result.value).toBeDefined();
  },
);

vtest(
  'meta._u === "" signals "default, not stored"',
  '`update(...)` checks for `_u === ""` to decide whether to fail with `updateFailed("Item not found")`.',
  () => {
    const synthetic = { _e: 'AppConfig', _v: 'v1', _u: '' };
    expect(synthetic._u).toBe('');
  },
);

vtest(
  "synthetic meta carries the schema's latestVersion",
  'When no row exists, the library still stamps `_v = schema.latestVersion` so downstream code does not have to special-case the default.',
  () => {
    const synthetic = { _e: 'AppConfig', _v: 'v1', _u: '' };
    expect(synthetic._v).toBeTruthy();
  },
);

vtest(
  'real stored rows have a non-empty _u',
  'After the first `put(...)` / `update(...)`, `_u` is an ISO timestamp; that is the in-band "exists" signal.',
  () => {
    const stored = {
      _e: 'AppConfig',
      _v: 'v1',
      _u: '2025-01-01T00:00:00.000Z',
    };
    expect(stored._u).not.toBe('');
  },
);

vtest(
  'pk and sk are both derived from the entity name only',
  'A single-entity has exactly one row; the key is `<EntityName>` for both `pk` and `sk`.',
  () => {
    const key = (entityName: string) => ({
      pk: entityName,
      sk: entityName,
    });
    expect(key('AppConfig')).toEqual({ pk: 'AppConfig', sk: 'AppConfig' });
  },
);

vtest(
  'partial merges only the listed fields',
  'Omitted fields keep their stored value.',
  () => {
    const existing = { theme: 'light', maxRetries: 3 };
    const merged = {
      ...existing,
      ...({ maxRetries: 5 } as Partial<typeof existing>),
    };
    expect(merged).toEqual({ theme: 'light', maxRetries: 5 });
  },
);

vtest(
  'an absent row fails with updateFailed (no implicit insert)',
  'Unlike `put`, `update` will not create a row from scratch — that is what the mandatory `default(...)` and `put(...)` are for.',
  () => {
    const meta = { _u: '' };
    const wouldFail = meta._u === '';
    expect(wouldFail).toBe(true);
  },
);

vtest(
  '_v is taken from the schema (never the caller)',
  'The input type is `Partial<Omit<T, "_v">>`.',
  () => {
    type In = Partial<Omit<{ a: string; _v: string }, '_v'>>;
    const u: In = {};
    expect('_v' in u).toBe(false);
  },
);

vtest(
  '_u is refreshed on every successful update',
  'Sync consumers see the touched timestamp on the broadcast envelope.',
  () => {
    const u = new Date().toISOString();
    expect(u).toMatch(/^\d{4}-\d{2}-\d{2}T/);
  },
);

vtest(
  'broadcast fires after the write, with meta._d: false',
  'Single-entity has no soft delete; the broadcast envelope still carries `_d: false` so subscribers can use one code path for both entity kinds.',
  () => {
    const entity = {
      value: { theme: 'dark' },
      meta: { _e: 'AppConfig', _v: 'v1', _u: '2025-01-01', _d: false },
    };
    expect(entity.meta._d).toBe(false);
  },
);

vtest(
  'composite primary key is (pk, sk)',
  'Every row is keyed by `(pk, sk)`. The names are configurable on the builder; the rest of the library is hard-wired to two-column keys.',
  () => {
    const table = SQLiteTable.make({ tableName: 't' })
      .primary('pk', 'sk')
      .build();
    expect(table.primary).toEqual({ pk: 'pk', sk: 'sk' });
  },
);

vtest(
  'secondary index columns are derived from .index(name, pk, sk)',
  'Each call to `.index(name, pkCol, skCol)` registers a column pair the entity layer can write into; the column names are the strings you passed.',
  () => {
    const table = SQLiteTable.make({ tableName: 't' })
      .primary('pk', 'sk')
      .index('IDX1', 'IDX1PK', 'IDX1SK')
      .index('IDX2', 'IDX2PK', 'IDX2SK')
      .build();
    expect(table.secondaryIndexMap).toEqual({
      IDX1: { pk: 'IDX1PK', sk: 'IDX1SK' },
      IDX2: { pk: 'IDX2PK', sk: 'IDX2SK' },
    });
  },
);

vtest(
  'tableName is exposed for error messages and RPC routing',
  'Errors raised by every operation embed the table name; the registry and command processor use it for diagnostics.',
  () => {
    const table = SQLiteTable.make({ tableName: 'std_data' })
      .primary('pk', 'sk')
      .build();
    expect(table.tableName).toBe('std_data');
  },
);

vtest(
  'setup() is an Effect, never a thunk',
  'You can compose it inside `Effect.gen`, retry it, or pipe a layer — it is _not_ run on `.build()`.',
  () => {
    const table = SQLiteTable.make({ tableName: 't' })
      .primary('pk', 'sk')
      .build();
    const effect = table.setup();
    expect(typeof effect).toBe('object');
    expect(effect).not.toBeNull();
  },
);

vtest(
  'index() throws synchronously for an unknown name',
  'The library catches typos at the call site rather than letting them surface as a SQLite error later.',
  () => {
    const table = SQLiteTable.make({ tableName: 't' })
      .primary('pk', 'sk')
      .build();
    expect(() => table.index('NOPE' as never)).toThrow(/not found/);
  },
);

vtest(
  'caller passes Omit<T, "_v">; library stamps _v',
  'Schema version belongs to the schema, never the caller.',
  () => {
    type Input = Omit<{ a: string; _v: string }, '_v'>;
    const v: Input = { a: 'x' };
    expect('_v' in v).toBe(false);
  },
);

vtest(
  'first put inserts (no existing row)',
  'The library calls `table.getItem` to detect existence, then chooses `putItem` vs `updateItem`.',
  () => {
    const existing = null;
    const branch = existing ? 'update' : 'insert';
    expect(branch).toBe('insert');
  },
);

vtest(
  'second put updates in place (existing row present)',
  'Idempotent put — the row is rewritten with new `_data`, `_v`, `_u`.',
  () => {
    const existing = { Item: { pk: 'X', sk: 'X' } };
    const branch = existing.Item ? 'update' : 'insert';
    expect(branch).toBe('update');
  },
);

vtest(
  '_u is a fresh ISO timestamp on every put',
  'Both branches (insert and update) generate a new `_u` at write time.',
  () => {
    const u = new Date().toISOString();
    expect(u).toMatch(/^\d{4}-\d{2}-\d{2}T/);
  },
);

vtest(
  'returned meta has no _d (single-entity has no soft delete)',
  'There is no concept of a tombstoned single-entity; the meta schema is `{ _e, _v, _u }`.',
  () => {
    const meta: { _e: string; _v: string; _u: string } = {
      _e: 'AppConfig',
      _v: 'v1',
      _u: new Date().toISOString(),
    };
    expect('_d' in meta).toBe(false);
  },
);

vtest(
  'index name is independent of pk / sk column names',
  'The first arg is a logical name (used by entities to refer to the index); the next two are the physical column names.',
  () => {
    const t = SQLiteTable.make({ tableName: 't' })
      .primary('pk', 'sk')
      .index('byEmail', 'IDX1PK', 'IDX1SK')
      .build();
    expect(t.secondaryIndexMap.byEmail).toEqual({
      pk: 'IDX1PK',
      sk: 'IDX1SK',
    });
  },
);

vtest(
  'multiple indexes accumulate in a typed map',
  'The builder is fully typed: each `.index(...)` widens `secondaryIndexMap` so downstream code can refer to the index by name without a cast.',
  () => {
    const t = SQLiteTable.make({ tableName: 't' })
      .primary('pk', 'sk')
      .index('IDX1', 'IDX1PK', 'IDX1SK')
      .index('IDX2', 'IDX2PK', 'IDX2SK')
      .build();
    expect(Object.keys(t.secondaryIndexMap).sort()).toEqual([
      'IDX1',
      'IDX2',
    ]);
  },
);

vtest(
  'index(name) returns an object with a .query method',
  'The accessor is the only way to reach secondary-index queries at the table layer.',
  () => {
    const t = SQLiteTable.make({ tableName: 't' })
      .primary('pk', 'sk')
      .index('IDX1', 'IDX1PK', 'IDX1SK')
      .build();
    const accessor = t.index('IDX1');
    expect(typeof accessor.query).toBe('function');
  },
);

vtest(
  'index(name) throws synchronously for unknown name',
  'Wrong name is a programmer error; surfaced at the call site, not as a SQL error.',
  () => {
    const t = SQLiteTable.make({ tableName: 't' })
      .primary('pk', 'sk')
      .build();
    expect(() => t.index('does-not-exist' as never)).toThrow(/not found/);
  },
);
